DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "PGlateximage.pl",
  "contextForm.pl",
  "parserPopUp.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$ab = list_random(
  [3, 4], [6, 8], [5, 12], [9, 12], [8, 15], [12, 16], [15, 20],
  [7, 24], [10, 24], [20, 21], [18, 24], [16, 30], [21, 28]
);
($a, $b) = @$ab;
$c = Real(sqrt($a**2 + $b**2));
Context()->variables->are(b => 'Real');
$proposed_solution = (random(0,1)) ? $b : $b + non_zero_random(-1, 2);
Context()->flags->set(reduceConstants => 0);
$left = Formula("$a^2 + b^2");
$right = Formula("$c^2");
Context("LimitedNumeric");
$lefteval = Real($left->eval(b => $proposed_solution));
$righteval = Real($right->eval(b => $proposed_solution));
$dropdown = DropDown(
  ["Yes, it is a solution.", "No, it is not a solution."],
  ($lefteval == $righteval) ? 0 : 1, showInStatic => 0
);

$introduction_image_1 = createLaTeXImage();
$introduction_image_1->addToPreamble(latexImagePreamble());
$introduction_image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \draw (0,0)
    --++ (4,0) node[below,pos=0.5] {\(a\)}
    --++ (0,3) node[right,pos=0.5] {\(b\)}
    --++ (-4,-3) node[above,sloped,pos=0.5] {\(c\)};
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
Consider a right triangle with legs of lengths [`a`] and [`b\text{,}`] and hypotenuse (the diagonal side) of length [`c\text{.}`]

>> [@image(insertGraph($introduction_image_1), width=>120, alt=>qq"A rectangle with sides labeled $a and b, and diagonal labeled $c")@]*  <<

A famous fact about such a triangle is that [`a^2+b^2=c^2\text{.}`] So if one leg [`a`] is [$a] inches long, and if the hypotenuse is [$c] inches long, then we have an equation [`[$left]=[$right]\text{.}`] Is the other leg [`[$proposed_solution]`] inches long?

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`=`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{=}`]'),
     PGML('[_]{$righteval}{3}'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
